module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const from = args.from || '#3b82f6';
const to = args.to || '#ef4444';
const value = parseFloat(args.value);
const hasMarker = Number.isFinite(value) && value >= 0;
const pos = Math.max(0, Math.min(100, value));
const markerCap = esc((args.marker || '').trim());
const heightRaw = parseFloat(args.height);
const height = Number.isFinite(heightRaw) ? Math.max(4, Math.min(60, heightRaw)) : 14;
const markerColor = (args.markercolor || '').trim();
const showLabels = String(args.labels === undefined ? 'true' : args.labels) !== 'false';
let rootStyle = `--sp-h:${height}px;`;
if (markerColor) rootStyle += `--sp-mk:${markerColor};`;
const marker = hasMarker
  ? `<div class="mdp-sp-marker" style="left:${pos}%;"><div class="mdp-sp-pin"></div>${markerCap ? `<div class="mdp-sp-cap">${markerCap}</div>` : ''}</div>`
  : '';
const ends = showLabels
  ? `<div class="mdp-sp-ends"><span>${esc(args.left || '')}</span><span>${esc(args.right || '')}</span></div>`
  : '';
return `\n\n<div class="mdp-mod-spectrum" style="${rootStyle}"><div class="mdp-sp-bar" style="background:linear-gradient(90deg, ${from}, ${to});">${marker}</div>` +
  ends + `</div>\n\n`;
